// Grupo de edad: los adultos y los menores no pueden contactar entre sí de ninguna manera
function isAdultU(userId) {
  const u = db.prepare('SELECT adult FROM users WHERE id = ?').get(userId);
  return u ? (u.adult == null ? true : !!u.adult) : true;
}
function sameAgeGroup(a, b) { return isAdultU(a) === isAdultU(b); }
function isBlocked(a, b) {
  return !!db.prepare('SELECT id FROM blocks WHERE (user_id = ? AND blocked_id = ?) OR (user_id = ? AND blocked_id = ?)').get(a, b, b, a);
}
