// ---------- algoritmo de recomendación ----------
// like +2, dislike -2, pasar -0.5 por cada género del libro; buscar un género también suma
const GENRE_LIST = ['fantasía','romance','misterio','terror','ciencia ficción','histórica','juvenil','aventura','drama','poesía','no ficción','clásicos','infantil'];
function genreAffinity(userId) {
  const rows = db.prepare('SELECT r.genres, x.action FROM reactions x JOIN reviews r ON r.id = x.review_id WHERE x.user_id = ?').all(userId);
  const scores = {}, weight = { like: 2, dislike: -2, skip: -0.5 };
  for (const row of rows) for (const g of row.genres.split(',')) {
    const genre = g.trim().toLowerCase();
    if (genre) scores[genre] = (scores[genre] || 0) + (weight[row.action] || 0);
  }
  // Tus votos 1-10 también cuentan: votar alto un libro trae más de su género
  const vrows = db.prepare('SELECT r.genres, v.value FROM votes v JOIN reviews r ON r.id = v.review_id WHERE v.user_id = ?').all(userId);
  for (const row of vrows) for (const g of row.genres.split(',')) {
    const genre = g.trim().toLowerCase();
    if (genre) scores[genre] = (scores[genre] || 0) + (row.value - 5.5) / 2;
  }
  // Las búsquedas recientes también cuentan: si buscas romance, te sale más romance
  const searched = db.prepare('SELECT term FROM searches WHERE user_id = ? ORDER BY id DESC LIMIT 40').all(userId);
  const searchBoost = {};
  for (const s of searched) for (const genre of GENRE_LIST) {
    if (s.term.includes(genre) || (genre.includes(s.term) && s.term.length >= 4)) {
      searchBoost[genre] = Math.min((searchBoost[genre] || 0) + 1.5, 4.5);
    }
  }
  for (const g in searchBoost) scores[g] = (scores[g] || 0) + searchBoost[g];
  return scores;
}

// ---------- biblioteca mundial (Open Library): libros infinitos ----------
const GENRE_SUBJECT = {
  'fantasía': 'fantasy', 'romance': 'romance', 'misterio': 'mystery', 'terror': 'horror',
  'ciencia ficción': 'science_fiction', 'histórica': 'historical_fiction', 'juvenil': 'young_adult',
  'aventura': 'adventure', 'drama': 'literary_fiction', 'poesía': 'poetry',
  'no ficción': 'biography', 'clásicos': 'classics', 'infantil': 'children'
};
const GENRE_AGE = {
  'juvenil': '12+', 'terror': '16+', 'romance': '14+', 'misterio': '14+', 'drama': '14+',
  'fantasía': '12+', 'ciencia ficción': '12+', 'histórica': '12+', 'aventura': 'todas las edades',
  'poesía': 'todas las edades', 'no ficción': 'todas las edades', 'clásicos': '12+', 'infantil': '6+'
};
function detectGenre(subjects) {
  if (!subjects || !subjects.length) return null; // sin datos NO se adivina (antes caía en drama/14+)
  const s = subjects.join(' ').toLowerCase();
  if (/children|picture book|infantil|board book|ages 4|ages 5|ages 6|ages 7|ages 8|preescolar|preschool/.test(s)) return 'infantil';
  if (/juvenile|young adult/.test(s)) return 'juvenil';
  if (/fantasy/.test(s)) return 'fantasía';
  if (/romance|love stories/.test(s)) return 'romance';
  if (/horror|terror/.test(s)) return 'terror';
  if (/science fiction/.test(s)) return 'ciencia ficción';
  if (/mystery|detective|thriller|crime/.test(s)) return 'misterio';
  if (/historical|history/.test(s)) return 'histórica';
  if (/poetry/.test(s)) return 'poesía';
  if (/biography|memoir|nonfiction|non-fiction/.test(s)) return 'no ficción';
  if (/classic/.test(s)) return 'clásicos';
  if (/adventure/.test(s)) return 'aventura';
  return 'drama';
}
