// Traductor doble: primero Google (rápido, sin clave), después MyMemory de respaldo.
async function translate(text, to) {
  if (to === 'en') return text;
  try {
    const d = await fetchJSON('https://translate.googleapis.com/translate_a/single?client=gtx&sl=en&tl=' + to + '&dt=t&q=' + encodeURIComponent(text), 6000);
    const t = (d[0] || []).map(x => x[0]).join('');
    if (t && t.length > 1) return t;
  } catch {}
  try {
    const data = await fetchJSON('https://api.mymemory.translated.net/get?q=' + encodeURIComponent(text.slice(0, 490)) + '&langpair=en|' + to, 6000);
    const t = data?.responseData?.translatedText;
    if (t && !/MYMEMORY WARNING|QUERY LENGTH/i.test(t)) return t;
  } catch {}
  return null;
}
