let botId = null;
function getBotId() {
  if (botId) return botId;
  let bot = db.prepare("SELECT id FROM users WHERE username = 'biblioteca'").get();
  if (!bot) {
    const info = db.prepare('INSERT INTO users (username, passhash, created) VALUES (?, ?, ?)')
      .run('biblioteca', hashPassword(crypto.randomBytes(24).toString('hex')), Date.now());
    bot = { id: Number(info.lastInsertRowid) };
  }
  botId = bot.id;
  return botId;
}
async function fetchJSON(url, ms = 6000) {
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), ms);
  try {
    const res = await fetch(url, { signal: ctrl.signal, headers: { 'User-Agent': 'PassBook/1.0' } });
    return await res.json();
  } finally { clearTimeout(t); }
}
async function importDoc(doc, genre, lang = 'es', requireDesc = true) {
  if (!doc || !doc.title || !doc.author_name?.length || !doc.cover_i) return false;
  if (db.prepare('SELECT id FROM reviews WHERE olid = ?').get(doc.key)) return false;
  if (db.prepare('SELECT id FROM reviews WHERE LOWER(title) = ? AND LOWER(author) = ?')
      .get(doc.title.toLowerCase(), doc.author_name[0].toLowerCase())) return false;
  const t = BOT_T[lang] || BOT_T.es;
  let g = genre || detectGenre(doc.subject);
  const year = doc.first_publish_year ? ` (${doc.first_publish_year})` : '';
  const rating = doc.ratings_average ? Math.min(10, Math.max(5, Math.round(doc.ratings_average * 2))) : 7 + Math.floor(Math.random() * 3);
  // Buscamos la descripción real del libro y la traducimos al idioma del usuario
  let rawDesc = null;
  try {
    const w = await fetchJSON('https://openlibrary.org' + doc.key + '.json', 3500);
    rawDesc = typeof w.description === 'string' ? w.description : w.description?.value;
    if (rawDesc) rawDesc = rawDesc.replace(/\[.*?\]|\(http[^)]*\)|https?:\S+/g, '').replace(/\s+/g, ' ').trim().slice(0, 480);
    if (!g && w.subjects) g = detectGenre(w.subjects); // el registro completo suele traer los temas
  } catch {}
  if (doc.number_of_pages_median && doc.number_of_pages_median <= 48) g = 'infantil'; // los álbumes cortos son infantiles
  if (/osito tito|lift[- ]the[- ]flap|pop-?up|toca,? toca|busy\b.*\bbook|libro de solapas/i.test(doc.title)) g = 'infantil';
  if (!g) g = 'aventura'; // desconocido → apto para todas las edades, nunca drama/14+
  // Sin descripción real no hay ficha: nada de sinopsis vacías tipo "es de los más leídos"
  if (requireDesc && (!rawDesc || rawDesc.length < 60)) return false;
  let desc = rawDesc, descLang = lang;
  if (desc && lang !== 'en') {
    desc = await translate(desc, lang);
    if (!desc) { desc = rawDesc; descLang = 'en'; } // mejor en inglés que sin historia; la app la traducirá al mostrarla
  }
  const info = [];
  if (doc.first_publish_year) info.push(`${t.pub} ${doc.first_publish_year}`);
  if (doc.ratings_average) info.push(`${t.nota} ${doc.ratings_average.toFixed(1)}/5${doc.ratings_count ? ' ' + t.conVotos + ' ' + doc.ratings_count + ' ' + t.votos : ''}`);
  const infoLine = info.length ? ` · ${info.join(' · ')}.` : '';
  const synopsis = desc
    ? `${desc}${infoLine ? '\n\n📊 ' + doc.title + infoLine : ''}`
    : `${t.syn(doc.title, doc.author_name[0], year, g)}${infoLine}`;
  db.prepare('INSERT INTO reviews (user_id, title, author, genres, rating, synopsis, text, age, pages, saga, image, olid, lang, created) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)')
    .run(getBotId(), doc.title.slice(0, 120), doc.author_name[0].slice(0, 80), g, rating, synopsis, t.text(g),
      GENRE_AGE[g] || '12+', doc.number_of_pages_median || null, null,
      'https://covers.openlibrary.org/b/id/' + doc.cover_i + '-L.jpg', doc.key, desc ? descLang : lang, Date.now());
  return true;
}
const OL_FIELDS = 'key,title,author_name,cover_i,first_publish_year,number_of_pages_median,ratings_average,ratings_count,subject';
async function discoverBooks(userId) {
  const lang = userLang(userId);
  const aff = genreAffinity(userId);
  const ranked = GENRE_LIST.slice().sort((a, b) => (aff[b] || 0) - (aff[a] || 0));
  const favorite = (aff[ranked[0]] || 0) > 0 ? ranked[0] : GENRE_LIST[Math.floor(Math.random() * GENRE_LIST.length)];
  const wildcard = GENRE_LIST[Math.floor(Math.random() * GENRE_LIST.length)];
  for (const genre of new Set([favorite, wildcard])) {
    const subject = GENRE_SUBJECT[genre];
    const offset = Math.floor(Math.random() * 150);
    try {
      const data = await fetchJSON(`https://openlibrary.org/search.json?subject=${subject}&sort=rating&limit=24&offset=${offset}&fields=${OL_FIELDS}`);
      await Promise.allSettled((data.docs || []).map(doc => importDoc(doc, genre, lang, true)));
    } catch {}
  }
}
// Importar desde Google Books (mejor con erratas, libros infantiles y en español)
function importGB(it, lang) {
  try {
    const v = it.volumeInfo || {};
    if (!v.title || !v.authors?.length) return false;
    const key = 'gb:' + it.id;
    if (db.prepare('SELECT id FROM reviews WHERE olid = ?').get(key)) return false;
    if (db.prepare('SELECT id FROM reviews WHERE LOWER(title) = ? AND LOWER(author) = ?').get(v.title.toLowerCase(), v.authors[0].toLowerCase())) return false;
    const img = v.imageLinks ? (v.imageLinks.thumbnail || v.imageLinks.smallThumbnail || '').replace('http://', 'https://') : null;
    if (!img) return false;
    const t = BOT_T[lang] || BOT_T.es;
    let g = detectGenre(v.categories);
    if (v.pageCount && v.pageCount <= 48) g = 'infantil'; // los álbumes cortos son infantiles
    if (/osito tito|lift[- ]the[- ]flap|pop-?up|toca,? toca|busy\b.*\bbook|libro de solapas/i.test(v.title)) g = 'infantil';
    if (!g) g = 'aventura'; // desconocido → todas las edades
    const desc = (v.description || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 600) || null;
    const rating = v.averageRating ? Math.min(10, Math.max(5, Math.round(v.averageRating * 2))) : 7 + Math.floor(Math.random() * 3);
    const year = v.publishedDate ? ` (${String(v.publishedDate).slice(0, 4)})` : '';
    const synopsis = desc || `${t.syn(v.title, v.authors[0], year, g)}`;
    db.prepare('INSERT INTO reviews (user_id, title, author, genres, rating, synopsis, text, age, pages, saga, image, olid, lang, created) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)')
      .run(getBotId(), v.title.slice(0, 120), v.authors[0].slice(0, 80), g, rating, synopsis, t.text(g),
        GENRE_AGE[g] || '12+', v.pageCount || null, null, img, key, desc ? 'auto' : lang, Date.now());
    return true;
  } catch { return false; }
}
async function importFromSearch(q, lang = 'es') {
  // Google Books PRIMERO: sus fichas traen mejores datos (género, páginas, descripción)
  try {
    const d = await fetchJSON('https://www.googleapis.com/books/v1/volumes?q=' + encodeURIComponent(q) + '&maxResults=8', 6000);
    for (const it of (d.items || [])) importGB(it, lang);
  } catch {}
  try {
    const data = await fetchJSON(`https://openlibrary.org/search.json?q=${encodeURIComponent(q)}&limit=6&fields=${OL_FIELDS}`);
    // En búsquedas directas sí aceptamos libros sin descripción: el usuario quiere ESE libro
    await Promise.allSettled((data.docs || []).map(doc => importDoc(doc, null, lang, false)));
  } catch {}
}

// Categoría de un short (para el algoritmo de recomendación de shorts)
function shortCat(t) {
  if (/Biblio/i.test(t)) return 'biblio';
  if (/frases/i.test(t)) return 'frases';
  if (/curiosidad|datos|palabras|sabías|libro más|primera novela|olor|velocidad|biblioteca/i.test(t)) return 'curiosidades';
  if (/reto|encuesta|pregunta|duelo|menciona|sigue a/i.test(t)) return 'retos';
  if (/humor|lectores|excusas|fases|página más|préstamo|tbr|mudanza|modo avión|marcapáginas|una estrella|presupuesto|dieta|spoiler/i.test(t)) return 'humor';
  if (/3 libros|sagas|joyas|romances|misterios|micro-reseña|tochos|distopías|cortitos|aventuras|poesía|clásicos que|históricas|no ficción/i.test(t)) return 'listas';
  if (/consejo|cómo|regla|trucos|passbook|leer antes|10 minutos/i.test(t)) return 'consejos';
  return 'general';
}

